export const UnitStatusSchema = z.enum(["rough","parsed","user_verified","stale"]).describe("Per-unit crystallization state (§6.0/§2.4) — distinct from `MathExpression.parse_status`\n(surface renderability) and from `ObjectStatus` (object lifecycle).");

export const UnitTypeSchema = z.enum(["theorem","lemma","proposition","corollary","definition","conjecture","claim","question","proof","proof_step","motivation","intuition","idea","proof_idea","remark","observation","warning","analogy","application","open_issue","return_later","note","example"]).describe("THE one user-facing math-flow label of a unit (§6.0). Carries *force and meaning*;\nform lives separately in `UnitContent.kind`. Absent (`Option::None`) = plain content.\nForms (list/group/embed/derivation/case_split) are deliberately NOT here — they are\ncontent kinds, never types (§6.0b).");

